class Solution:
    def __init__(self): self.buf4, self.p, self.s = [""], 0, 0
    def read(self, buf, n):
        i = 0
        while i < n:
            if self.p == self.s:
                self.s = read4(self.buf4)
                self.p = 0
                if self.s == 0: break
            buf[i] = self.buf4[self.p]
            i += 1; self.p += 1
        return i

